INSERT INTO response_master (id, response_text, category, embedding, enabled, updated_at)
SELECT
    id,
    response_text,
    category,
    NULL,
    true,
    now()
FROM seed_responses
ON CONFLICT (id)
DO UPDATE SET
    embedding = CASE
        WHEN response_master.response_text IS DISTINCT FROM EXCLUDED.response_text THEN NULL
        ELSE response_master.embedding
    END,
    response_text = EXCLUDED.response_text,
    category = EXCLUDED.category,
    enabled = true,
    updated_at = now();
